import React from "react";

export default function LandingPage() {
  return (
    <div className="bg-[#10141a] text-white font-sans">
      {/* Navbar */}
      <nav className="fixed w-full top-0 z-50 bg-black/60 backdrop-blur">
        <div className="max-w-7xl mx-auto px-6 py-4 flex justify-between items-center">
          <h1 className="text-xl font-bold text-cyan-400">Techvruk</h1>
          <div className="hidden md:flex gap-6 text-gray-400">
            <a href="#programs">Programs</a>
            <a href="#community">Community</a>
            <a href="#contact">Contact</a>
          </div>
          <button className="bg-cyan-400 text-black px-4 py-2 rounded">
            Join Now
          </button>
        </div>
      </nav>

      {/* Hero */}
      <section className="min-h-screen flex items-center justify-center text-center pt-20">
        <div>
          <h1 className="text-5xl md:text-7xl font-bold mb-6">
            Build the Future with{" "}
            <span className="text-cyan-400">Techvruk</span>
          </h1>
          <p className="text-gray-400 max-w-xl mx-auto mb-8">
            Empowering engineers through innovation, training, and
            collaboration.
          </p>
          <div className="flex gap-4 justify-center">
            <button className="bg-cyan-400 text-black px-6 py-3 rounded">
              Join Now
            </button>
            <button className="border border-cyan-400 px-6 py-3 rounded">
              Explore Programs
            </button>
          </div>
        </div>
      </section>

      {/* Value Cards */}
      <section className="py-20 px-6 grid md:grid-cols-4 gap-6 max-w-7xl mx-auto">
        {[
          "Innovation Contests",
          "Industry Training",
          "Awards",
          "Networking",
        ].map((item, i) => (
          <div
            key={i}
            className="bg-gray-800 p-6 rounded hover:scale-105 transition"
          >
            <h3 className="font-bold">{item}</h3>
          </div>
        ))}
      </section>

      {/* Programs */}
      <section id="programs" className="py-20 px-6">
        <h2 className="text-3xl font-bold text-center mb-10">
          Programs & Opportunities
        </h2>
        <div className="grid md:grid-cols-2 gap-6 max-w-7xl mx-auto">
          {[1, 2].map((item) => (
            <div key={item} className="bg-gray-800 rounded overflow-hidden">
              <img
                src="https://via.placeholder.com/600x300"
                alt="program"
                className="w-full"
              />
              <div className="p-6">
                <h3 className="text-xl font-bold mb-2">Program {item}</h3>
                <p className="text-gray-400 mb-4">
                  Brief description of program.
                </p>
                <button className="bg-cyan-400 text-black px-4 py-2 rounded">
                  Apply Now
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Stats */}
      <section className="py-16 text-center bg-black">
        <div className="grid md:grid-cols-3 gap-6">
          <div>
            <h2 className="text-4xl text-cyan-400">10,000+</h2>
            <p>Students</p>
          </div>
          <div>
            <h2 className="text-4xl text-cyan-400">200+</h2>
            <p>Events</p>
          </div>
          <div>
            <h2 className="text-4xl text-cyan-400">50+</h2>
            <p>Mentors</p>
          </div>
        </div>
      </section>

      {/* CTA */}
      <section className="py-20 text-center">
        <h2 className="text-4xl font-bold mb-6">
          Ready to engineer your future?
        </h2>
        <button className="bg-cyan-400 text-black px-8 py-3 rounded">
          Join Now
        </button>
      </section>

      {/* Footer */}
      <footer className="text-center py-6 text-gray-500 border-t border-gray-800">
        © 2026 Techvruk
      </footer>
    </div>
  );
}
